#!/usr/bin/env node
// bundle-wasm.js — Bundles wasm-pack output into a single self-contained ES module.
//
// Replaces the fragile sed-based transforms in build.sh with proper string
// manipulation that validates each transformation step.

const { readFileSync, writeFileSync, statSync } = require('fs');
const { join } = require('path');

const CRATE_DIR = join(__dirname, '..', 'media', 'crate');
const PKG_DIR = join(CRATE_DIR, 'pkg');
const OUT_FILE = join(__dirname, '..', 'media', 'core.js');

const WASM_PATH = join(PKG_DIR, 'vcd_parser_bg.wasm');
const JS_PATH = join(PKG_DIR, 'vcd_parser.js');

// --- Validate inputs ---

for (const f of [WASM_PATH, JS_PATH]) {
  try {
    const stat = statSync(f);
    if (stat.size === 0) {
      console.error(`Error: file is empty: ${f}`);
      process.exit(1);
    }
  } catch {
    console.error(`Error: expected file not found: ${f}`);
    process.exit(1);
  }
}

// --- Base64-encode the WASM binary ---

console.log('Encoding WASM binary...');
const wasmBytes = readFileSync(WASM_PATH);
const wasmB64 = wasmBytes.toString('base64');

// --- Read and transform the JS glue code ---

console.log('Transforming JS glue code...');
let jsGlue = readFileSync(JS_PATH, 'utf-8');

// 1. Remove @ts-self-types comment
jsGlue = jsGlue.replace(/^\/\* @ts-self-types.*\*\/\s*/m, '');

// 2. Strip `export` from declarations (class, function, const, let, var)
//    so they become module-scoped instead of individually exported.
jsGlue = jsGlue.replace(/^export (function |class |const |let |var )/gm, '$1');

// 3. Remove barrel export line: `export { initSync, __wbg_init as default };`
jsGlue = jsGlue.replace(/^export \{[^}]*\};?\s*$/gm, '');

// 4. Remove import.meta.url fallback (we supply WASM bytes directly)
jsGlue = jsGlue.replace(/^.*import\.meta\.url.*$/gm, '');

// --- Assemble the output ---

const preamble = `// Auto-generated by scripts/bundle-wasm.js — do not edit by hand
const _wasmB64 = "${wasmB64}";
function _b64decode(b64) {
  const bin = atob(b64);
  const bytes = new Uint8Array(bin.length);
  for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
  return bytes;
}
const wasmBytes = _b64decode(_wasmB64);
`;

const footer = `
const __module = Object.freeze({ __proto__: null, Radix, License, Machine, VCD, VCDNode });
export default async () => (await __wbg_init(wasmBytes), __module);
`;

const output = preamble + jsGlue + footer;

writeFileSync(OUT_FILE, output);
console.log(`Done — wrote ${OUT_FILE} (${output.length} bytes)`);
